export default {
  async submitPreferences() {
    //const createdUser = await createUser.run();
    //const userId = String(createdUser.id);
		const userId = "0"

    const genreIds = (GenreCheckboxGroup.selectedValues || []).map(String);
    const characterIds = (CharacterCheckboxGroup.selectedValues || []).map(String);
    const publisherIds = (PublisherCheckboxGroup.selectedValues || []).map(String);
    const powerIds = (PowerCheckboxGroup.selectedValues || []).map(String);
    const teamIds = (TeamCheckboxGroup.selectedValues || []).map(String);

    for (const genreId of genreIds) {
      await updatePreferredGenre.run({ userId, genreId });
    }

    for (const characterId of characterIds) {
      await updatePreferredCharacter.run({ userId, characterId });
    }

    for (const publisherId of publisherIds) {
      await updatePreferredPublisher.run({ userId, publisherId });
    }

    for (const powerId of powerIds) {
      await updatePreferredPower.run({ userId, powerId });
    }

    for (const teamId of teamIds) {
      await updatePreferredTeam.run({ userId, teamId });
    }

    return {
      userId,
      genreIds,
      characterIds,
      publisherIds,
      powerIds,
      teamIds
    };
  }
}
